     1→/**
     2→ * AI Routing Stage
     3→ *
     4→ * Stage 8 of the EmailCategorizer pipeline. Determines whether emails need AI classification
     5→ * based on confidence scores from multi-label selection. Routes high-confidence emails directly
     6→ * to final decision while sending uncertain cases through AI classification for enhancement.
     7→ *
     8→ * ROUTING DECISION LOGIC:
     9→ * - High Confidence (>=15): Skip AI - rule-based results are reliable
    10→ * - Medium Confidence (8-14): Route to AI - can benefit from enhanced classification
    11→ * - Very Low Confidence (<3): Skip AI - likely unclassifiable even with AI
    12→ * - No Labels Selected: Route to AI - last chance for classification
    13→ * - Hard Assertions: Skip AI - domain-based results are authoritative
    14→ */
    15→
    16→import { EmailMessage, ClassificationSession } from '../types';
    17→import { ClassificationResult, SelectedLabel, CandidateScore } from '../types/classification-result';
    18→import { ConfidenceThresholds } from './types';
    19→import {
    20→  validateEmailInput,
    21→  validateSessionInput,
    22→  validateConfigInput,
    23→  validateConfidenceScore,
    24→} from '../utils/validation';
    25→
    26→/**
    27→ * AI Routing Configuration
    28→ *
    29→ * THREE-THRESHOLD LOGIC for AI routing decisions:
    30→ *
    31→ * 1. highConfidenceThreshold: Score >= this → Skip AI (rule-based result reliable)
    32→ *    - Example: score = 0.9, highThreshold = 0.8 → Skip AI (confident in rules)
    33→ *
    34→ * 2. lowConfidenceThreshold: Score < this → Skip AI (too uncertain for AI to help)
    35→ *    - Example: score = 0.2, lowThreshold = 0.3 → Skip AI (likely unclassifiable)
    36→ *
    37→ * 3. aiRequiredThreshold: Within medium range, score >= this → Route to AI
    38→ *    - Medium confidence range: lowConfidenceThreshold <= score < highConfidenceThreshold
    39→ *    - Example: score = 0.6, aiRequired = 0.5, low = 0.3, high = 0.8 → Route to AI
    40→ *    - Example: score = 0.4, aiRequired = 0.5, low = 0.3, high = 0.8 → Skip AI (not worth cost)
    41→ *
    42→ * THRESHOLD ORDERING REQUIREMENT: low < aiRequired < high
    43→ *
    44→ * AI ROUTING DECISION FLOW:
    45→ * - IF score >= highConfidenceThreshold → Skip AI (high confidence)
    46→ * - ELSE IF score < lowConfidenceThreshold → Skip AI (very low confidence)
    47→ * - ELSE IF lowConfidenceThreshold <= score < highConfidenceThreshold (medium confidence):
    48→ *   - IF score >= aiRequiredThreshold → Route to AI (worth the cost)
    49→ *   - ELSE → Skip AI (below cost threshold)
    50→ */
    51→export interface AIRoutingConfig {
    52→  settings: {
    53→    aiRouting: {
    54→      highConfidenceThreshold: number;
    55→      aiRequiredThreshold: number;
    56→      skipAiConditions: string[];
    57→    };
    58→  };
    59→  confidenceThresholds: ConfidenceThresholds & {
    60→    aiClassificationRequired?: number;
    61→  };
    62→}
    63→
    64→// Routing decision result
    65→export interface RoutingDecision {
    66→  routeToAi: boolean;
    67→  routingReason: string;
    68→  confidenceAssessment: string;
    69→  costConsideration: string;
    70→}
    71→
    72→// Simplified explainability trace for AI routing
    73→export interface AIRoutingExplainabilityTrace {
    74→  stageType: string;
    75→  stageOrder: number;
    76→  decisionFactors: {
    77→    primaryScore: number;
    78→    thresholdAnalysis: {
    79→      highConfidenceThreshold: number;
    80→      aiRequiredThreshold: number;
    81→      lowConfidenceThreshold: number;
    82→      primaryScore: number;
    83→      thresholdMet: string;
    84→    };
    85→    competitorAnalysis: {
    86→      closeCompetitorsFound: boolean;
    87→      competitorCount: number;
    88→      multipleLabelsSelected: boolean;
    89→    };
    90→  };
    91→  reasoning: string;
    92→  processingMetadata: {
    93→    processingTimeMs: number;
    94→    inputLabelsCount: number;
    95→    candidateScoresCount: number;
    96→  };
    97→}
    98→
    99→// Stage result interface
   100→export interface AIRoutingResult {
   101→  routingDecision: RoutingDecision;
   102→  routingBranch: 'aiClassification' | 'directToMerge';
   103→  explainabilityTrace: AIRoutingExplainabilityTrace;
   104→}
   105→
   106→/**
   107→ * AI Routing Stage Implementation
   108→ *
   109→ * Analyzes classification confidence and determines optimal routing strategy
   110→ * for email processing continuation.
   111→ *
   112→ * CANONICAL SIGNATURE: (email, session, result, config) => void
   113→ * Mutates result.needsAiClassification and adds explainability trace
   114→ */
   115→export function aiRoutingStage(
   116→  email: EmailMessage,
   117→  session: ClassificationSession,
   118→  result: ClassificationResult,
   119→  config: AIRoutingConfig
   120→): void {
   121→  const startTime = Date.now();
   122→
   123→  // Validate inputs
   124→  validateInputs(email, session, result, config);
   125→
   126→  // Extract data from result object
   127→  const selectedLabels = result.selectedLabels;
   128→  const candidateScores = result.candidateScores;
   129→
   130→  // FIXME with T077: Unify scoring scales across stages before using thresholds
   131→  // Extract routing thresholds from config.settings.aiRouting (these are on 0-1 normalized scale)
   132→  // NOTE: config.confidenceThresholds.* are ABSOLUTE SCORES (0-15+ scale) from rule scoring - DO NOT USE HERE
   133→  const highConfidenceThreshold = config.settings.aiRouting.highConfidenceThreshold || 0.8;
   134→
   135→  const aiRequiredThreshold = config.settings.aiRouting.aiRequiredThreshold || 0.5;
   136→
   137→  // FIXME T078: Add lowConfidenceThreshold to config instead of hardcoding
   138→  // lowConfidenceThreshold not currently in config, use sensible default
   139→  const lowConfidenceThreshold = 0.3;
   140→
   141→  const skipAiConditions = config.settings.aiRouting.skipAiConditions || [];
   142→
   143→  // Make routing decision
   144→  const routingDecision = makeRoutingDecision(
   145→    selectedLabels,
   146→    candidateScores,
   147→    result, // Pass result for normalized confidence value
   148→    highConfidenceThreshold,
   149→    aiRequiredThreshold,
   150→    lowConfidenceThreshold,
   151→    skipAiConditions
   152→  );
   153→
   154→  // Generate explainability trace
   155→  const explainabilityTrace = generateExplainabilityTrace(
   156→    selectedLabels,
   157→    candidateScores,
   158→    routingDecision,
   159→    {
   160→      highConfidenceThreshold: highConfidenceThreshold,
   161→      aiRequiredThreshold: aiRequiredThreshold,
   162→      lowConfidenceThreshold: lowConfidenceThreshold,
   163→    },
   164→    startTime
   165→  );
   166→
   167→  // Mutate result in place
   168→  result.needsAiClassification = routingDecision.routeToAi;
   169→  result.aiRoutingUsed = routingDecision.routeToAi; // Also update aiRoutingUsed for backward compatibility
   170→
   171→  // Initialize explainabilityTrace if not exists (defensive check)
   172→  if (!result.explainabilityTrace) {
   173→    throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
   174→  }
   175→
   176→  // Add explainability trace to result - store in appropriate field
   177→  if (!result.explainabilityTrace.aiRouting) {
   178→    result.explainabilityTrace.aiRouting = {
   179→      routingDecision: routingDecision.routeToAi ? 'fullClassification' : 'skipAi',
   180→      highConfidenceThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.highConfidenceThreshold,
   181→      aiRequiredThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.aiRequiredThreshold,
   182→      skipConditions: [],
   183→      reason: routingDecision.routingReason,
   184→    };
   185→  }
   186→
   187→  // Track processing time
   188→  result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
   189→  result.explainabilityTrace.stageTimings['aiRouting'] = explainabilityTrace.processingMetadata.processingTimeMs;
   190→}
   191→
   192→/**
   193→ * Validate input parameters
   194→ */
   195→function validateInputs(
   196→  email: EmailMessage,
   197→  session: ClassificationSession,
   198→  result: ClassificationResult,
   199→  config: AIRoutingConfig
   200→): void {
   201→  validateEmailInput(email);
   202→  validateSessionInput(session);
   203→  validateConfigInput(config);
   204→
   205→  if (!result) {
   206→    throw new Error('Classification result is required');
   207→  }
   208→
   209→  if (!result.selectedLabels) {
   210→    throw new Error('Selected labels are required in result');
   211→  }
   212→
   213→  if (!result.candidateScores) {
   214→    throw new Error('Candidate scores are required in result');
   215→  }
   216→
   217→  // Validate confidence scores
   218→  for (const label of result.selectedLabels) {
   219→    validateConfidenceScore(label.confidence);
   220→  }
   221→}
   222→
   223→/**
   224→ * Core routing decision logic
   225→ *
   226→ * Implements the three-threshold AI routing strategy:
   227→ * - High confidence (>= highThreshold): Skip AI - rule-based results are reliable
   228→ * - Low confidence (< lowThreshold): Skip AI - too uncertain for AI to help
   229→ * - Medium confidence (lowThreshold <= score < highThreshold):
   230→ *   - If score >= aiRequiredThreshold: Route to AI (worth the cost)
   231→ *   - Otherwise: Skip AI (below cost threshold)
   232→ *
   233→ * @param selectedLabels - Labels selected by multi-label selection stage
   234→ * @param candidateScores - All candidate category scores
   235→ * @param result - Classification result with normalized confidence (0-1 scale)
   236→ * @param highConfidenceThreshold - Skip AI if score >= this (confident in rules)
   237→ * @param aiRequiredThreshold - Within medium range, route to AI if score >= this
   238→ * @param lowConfidenceThreshold - Skip AI if score < this (too uncertain)
   239→ * @param skipAiConditions - Additional conditions to skip AI (e.g., hardAssertion)
   240→ * @returns Routing decision with reasoning
   241→ */
   242→function makeRoutingDecision(
   243→  selectedLabels: SelectedLabel[],
   244→  candidateScores: Record<string, CandidateScore>,
   245→  result: ClassificationResult,
   246→  highConfidenceThreshold: number,
   247→  aiRequiredThreshold: number,
   248→  lowConfidenceThreshold: number,
   249→  skipAiConditions: string[]
   250→): RoutingDecision {
   251→  // Case 1: No labels selected - route to AI for last chance classification
   252→  if (selectedLabels.length === 0) {
   253→    return {
   254→      routeToAi: true,
   255→      routingReason:
   256→        'No labels selected due to insufficient confidence in rule-based classification - AI may recover classification',
   257→      confidenceAssessment: 'noClassification',
   258→      costConsideration: 'recoveryAttempt',
   259→    };
   260→  }
   261→
   262→  // Case 2: Check for hard assertions (skip AI condition)
   263→  // Hard assertions are domain-based classifications that are authoritative
   264→  if (skipAiConditions.includes('hardAssertion')) {
   265→    const hasHardAssertion = Object.values(candidateScores).some((score) => score.hardAssertion);
   266→    if (hasHardAssertion) {
   267→      return {
   268→        routeToAi: false,
   269→        routingReason: 'hard assertion applied - domain-based classification is authoritative',
   270→        confidenceAssessment: 'hardAssertionSkip',
   271→        costConsideration: 'aiUnnecessary',
   272→      };
   273→    }
   274→  }
   275→
   276→  // Case 3: Analyze primary label confidence for threshold-based routing
   277→  // NOTE: Use result.confidence (normalized 0-1 scale) not selectedLabels[].confidence (0-100 scale)
   278→  const primaryLabel = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
   279→
   280→  // Get normalized confidence from result (set by multi-label selection)
   281→  // If not set, this is an error - we should always have confidence by now
   282→  if (result.confidence === undefined || result.confidence === null) {
   283→    throw new Error('CRITICAL: result.confidence not set by multi-label selection stage');
   284→  }
   285→  const primaryScore = result.confidence; // Normalized to 0-1 scale by multi-label selection
   286→
   287→  // High confidence threshold check: score >= highThreshold → Skip AI
   288→  // Rule-based results are reliable at this confidence level
   289→  if (primaryScore >= highConfidenceThreshold) {
   290→    return {
   291→      routeToAi: false,
   292→      routingReason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
   293→      confidenceAssessment: 'highConfidence',
   294→      costConsideration: 'aiUnnecessary',
   295→    };
   296→  }
   297→
   298→  // Low confidence threshold check: score < lowThreshold → Skip AI
   299→  // Too uncertain for AI to provide meaningful improvement
   300→  if (primaryScore < lowConfidenceThreshold) {
   301→    return {
   302→      routeToAi: false,
   303→      routingReason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
   304→      confidenceAssessment: 'veryLowConfidence',
   305→      costConsideration: 'aiIneffective',
   306→    };
   307→  }
   308→
   309→  // Medium confidence range: lowThreshold <= score < highThreshold
   310→  // Analyze additional factors to determine if AI is worth the cost
   311→  const hasMultipleLabels = selectedLabels.length > 1;
   312→  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);
   313→
   314→  // Build routing reason with contextual factors
   315→  if (primaryScore >= lowConfidenceThreshold && primaryScore < highConfidenceThreshold) {
   316→    let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
   317→    let costConsideration = 'beneficialEnhancement';
   318→
   319→    // Additional factors that increase AI value
   320→    if (hasCloseCompetitors) {
   321→      aiRoutingReason += ' with close competing categories';
   322→      costConsideration = 'disambiguationValuable';
   323→    }
   324→
   325→    if (hasMultipleLabels) {
   326→      aiRoutingReason += ' with multiple labels selected';
   327→      costConsideration = 'multiLabelValidation';
   328→    }
   329→
   330→    // Apply aiRequiredThreshold: only route to AI if score is high enough
   331→    // This prevents routing low-medium confidence emails that won't benefit from AI
   332→    if (primaryScore >= aiRequiredThreshold) {
   333→      return {
   334→        routeToAi: true,
   335→        routingReason:
