    it('should not consider distant competitors as close', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 14.0,
          score: 14.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Clear financial with distant competitors',
        },
      ];
      result.candidateScores = {
        financial: { score: 14.0, confidence: 14.0, decision: 'selected' },
