describe('Edge Cases and Error Handling', () => {
  it('should handle missing primary label gracefully', () => {
    const result = createClassificationResult('test-123', 'session-123', 0);
    result.selectedLabels = [
      {
        category: 'financial',
        confidence: 10.0,
        score: 10.0,
        isPrimary: false,
        labelOrder: 1,
        subtype: 'receipt',
        selectionRationale: 'No primary flag set',
      },
    ];
    result.candidateScores = {
      financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
    };

    aiRoutingStage(mockEmail, mockSession, result, mockConfig);

    // Should use first label as primary when no primary flag is set
    expect(result.needsAiClassification).toBe(true);
    expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
    expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
    expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
  });

  it('should handle malformed classification input', () => {
    const result = createClassificationResult('test-123', 'session-123', 0);
    result.selectedLabels = [
      {
        category: 'financial',
        confidence: NaN,
        score: NaN,
        isPrimary: true,
        labelOrder: 1,
        subtype: 'receipt',
        selectionRationale: 'Invalid confidence score',
      },
    ];
    result.candidateScores = {};

    expect(() => {
      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
    }).toThrow('Invalid confidence score');
  });

  it('should handle custom confidence thresholds', () => {
    const customConfig = {
      ...mockConfig,
      settings: {
        aiRouting: {
          highConfidenceThreshold: 20,
          aiRequiredThreshold: 10,
          skipAiConditions: [],
        },
      },
    };

    const result = createClassificationResult('test-123', 'session-123', 0);
    result.selectedLabels = [
      {
        category: 'financial',
        confidence: 18.0,
        score: 18.0,
        isPrimary: true,
        labelOrder: 1,
        subtype: 'statement',
        selectionRationale: 'High confidence with custom thresholds',
      },
    ];
    result.candidateScores = {
      financial: { score: 18.0, confidence: 18.0, decision: 'selected' },
    };

    aiRoutingStage(mockEmail, mockSession, result, customConfig);

    // With higher threshold (20), score of 18 should route to AI
    expect(result.needsAiClassification).toBe(true);
    expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
    expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(20);
  });
});

