/**
 * Unit Tests for AI Routing Stage
 *
 * Following TDD approach - these tests MUST FAIL before implementation.
 * This stage determines whether emails need AI classification based on confidence scores.
 */

import { aiRoutingStage } from '../../src/stages/ai-routing';
import { CandidateScore } from '../../src/types/classification-result';
import { EmailMessage, ClassificationSession } from '../../src/types';
import { createClassificationResult } from '../../src/utils/initialization';

describe('AI Routing Stage', () => {
  const mockConfig = {
    settings: {
      aiRouting: {
        highConfidenceThreshold: 0.8, // Normalized 0-1 scale (was 15 on absolute scale)
        aiRequiredThreshold: 0.5, // Normalized 0-1 scale (was 12 on absolute scale)
        skipAiConditions: ['hardAssertion'],
      },
    },
    confidenceThresholds: {
      highConfidence: 15,
      mediumConfidence: 8,
      lowConfidence: 3,
      secondaryLabelMinGap: 5,
      aiClassificationRequired: 12,
      manualReviewRequired: 2,
    },
  };

  const mockEmail: EmailMessage = {
    id: 'test-123',
    threadId: 'thread-123',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test email' },
        { name: 'From', value: 'Test User <test@example.com>' },
        { name: 'To', value: 'User <user@example.com>' },
      ],
    },
    subject: 'Test email',
    from: { email: 'test@example.com', name: 'Test User', raw: 'Test User <test@example.com>' },
    to: [{ email: 'user@example.com', name: 'User', raw: 'User <user@example.com>' }],
    bodyPlain: 'Test email body',
    bodyHtml: '<p>Test email body</p>',
    date: new Date('2024-01-01T10:00:00Z'),
    isProcessed: false,
    processingPriority: 1,
  };

  const mockSession: ClassificationSession = {
    id: 'session-123',
    startedAt: new Date('2024-01-01T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'parallel',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-version',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  describe('High Confidence Routing', () => {
    it('should skip AI for high confidence primary labels (>=0.8)', () => {
      // Create properly initialized result
      const result = createClassificationResult('test-123', 'session-123', 0);

      // Populate with high confidence classification data
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 16.5,
          score: 16.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'High confidence financial classification',
        },
      ];
      result.candidateScores = {
        financial: { score: 16.5, confidence: 16.5, decision: 'selected' },
      };
      result.confidence = 0.85; // Normalized 0-1 scale used by AI routing

      // Execute stage - mutates result in place
      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      // Verify routing decision
      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting).toBeDefined();
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('High confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('0.85');
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(0.8);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(0.5);
    });

    it('should skip AI when hard assertion condition is met', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 12.0,
          score: 12.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Hard assertion based on domain match',
        },
      ];
      result.candidateScores = {
        financial: { score: 12.0, confidence: 12.0, decision: 'selected', hardAssertion: true },
      };
      result.confidence = 0.6; // Normalized confidence (hard assertion overrides threshold logic)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('hard assertion');
    });
  });

