      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('multiple labels');
    });

    it('should route to AI when close competitors exist', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'commerceLogistics',
          confidence: 11.0,
          score: 11.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'shippingUpdate',
          selectionRationale: 'Close competition with travel category',
        },
      ];
      result.candidateScores = {
