    });

    it('should route to AI when close competitors exist', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'commerceLogistics',
          confidence: 11.0,
          score: 11.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'shippingUpdate',
          selectionRationale: 'Close competition with travel category',
        },
      ];
      result.candidateScores = {
        commerceLogistics: { score: 11.0, confidence: 11.0, decision: 'selected' },
        travel: { score: 9.5, confidence: 9.5, decision: 'candidate' },
        personal: { score: 8.8, confidence: 8.8, decision: 'candidate' },
      };
      result.confidence = 0.6; // Normalized medium confidence with close competitors

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('close competing categories');
    });
  });

  describe('Low Confidence Routing', () => {
    it('should skip AI for very low confidence scores (<0.3)', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'uncategorized',
          confidence: 2.1,
          score: 2.1,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'needsReview',
          selectionRationale: 'Very low confidence classification',
        },
      ];
      result.candidateScores = {
        uncategorized: { score: 2.1, confidence: 2.1, decision: 'selected' },
      };
      result.confidence = 0.15; // Normalized very low confidence (< 0.3)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('likely unclassifiable');
    });

    it('should skip AI for scores below AI routing threshold but above low threshold', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'systemNotifications',
          confidence: 6.5,
          score: 6.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'serviceStatus',
          selectionRationale: 'Below AI routing threshold',
        },
      ];
      result.candidateScores = {
        systemNotifications: { score: 6.5, confidence: 6.5, decision: 'selected' },
      };
      result.confidence = 0.4; // Normalized medium-low confidence (>= 0.3, < 0.5)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('below AI routing threshold');
    });
  });

  describe('No Labels Selected', () => {
    it('should route to AI when no labels are selected', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [];
      result.candidateScores = {};
      result.confidence = 0; // No classification = 0 confidence

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('No labels selected');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('AI may recover');
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing primary label gracefully', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 10.0,
          score: 10.0,
          isPrimary: false,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'No primary flag set',
        },
      ];
      result.candidateScores = {
        financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
      };
      result.confidence = 0.6; // Medium confidence

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      // Should use first label as primary when no primary flag is set
      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
    });

    it('should handle malformed classification input', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: NaN,
          score: NaN,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Invalid confidence score',
        },
      ];
      result.candidateScores = {};

      expect(() => {
        aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      }).toThrow('Invalid confidence score');
    });

    it('should handle custom confidence thresholds', () => {
      const customConfig = {
        ...mockConfig,
        settings: {
          aiRouting: {
            highConfidenceThreshold: 0.9, // Normalized 0-1 scale (higher than default 0.8)
            aiRequiredThreshold: 0.6, // Normalized 0-1 scale (higher than default 0.5)
            skipAiConditions: [],
          },
        },
      };

      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 18.0,
          score: 18.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'High confidence with custom thresholds',
        },
      ];
      result.candidateScores = {
        financial: { score: 18.0, confidence: 18.0, decision: 'selected' },
      };
      result.confidence = 0.85; // Normalized confidence (< 0.9 high threshold, >= 0.6 AI required)

      aiRoutingStage(mockEmail, mockSession, result, customConfig);

      // With higher threshold (0.9), score of 0.85 should route to AI
      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(0.9);
    });
  });

  describe('Close Competitors Analysis', () => {
    it('should correctly identify close competitors within gap threshold', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'travel',
          confidence: 12.0,
          score: 12.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'flightAlert',
          selectionRationale: 'Travel with commerce logistics competition',
        },
      ];
      result.candidateScores = {
        travel: { score: 12.0, confidence: 12.0, decision: 'selected' },
        commerceLogistics: { score: 10.5, confidence: 10.5, decision: 'candidate' },
        personal: { score: 9.8, confidence: 9.8, decision: 'candidate' },
        financial: { score: 4.0, confidence: 4.0, decision: 'rejected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('close competing categories');
    });

    it('should not consider distant competitors as close', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 14.0,
          score: 14.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Clear financial with distant competitors',
        },
      ];
      result.candidateScores = {
        financial: { score: 14.0, confidence: 14.0, decision: 'selected' },
        actionable: { score: 8.0, confidence: 8.0, decision: 'candidate' },
        personal: { score: 6.0, confidence: 6.0, decision: 'candidate' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).not.toContain('close competing categories');
    });
  });

  describe('Explainability and Audit Trail', () => {
    it('should generate complete explainability trace', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'actionable',
          confidence: 11.5,
          score: 11.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'explicitAction',
          selectionRationale: 'Action required classification',
        },
      ];
      result.candidateScores = {
        actionable: { score: 11.5, confidence: 11.5, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.explainabilityTrace.aiRouting).toBeDefined();
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);
      expect(result.explainabilityTrace.aiRouting?.skipConditions).toEqual([]);
      expect(result.explainabilityTrace.aiRouting?.reason).toBeDefined();
      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeDefined();
      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeGreaterThanOrEqual(0);
    });

    it('should include threshold configuration in trace', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'subscriptionContent',
          confidence: 13.0,
          score: 13.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'newsletter',
          selectionRationale: 'Newsletter classification',
        },
      ];
      result.candidateScores = {
        subscriptionContent: { score: 13.0, confidence: 13.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
    });
  });

  describe('Performance Requirements', () => {
    it('should process routing decision in under 50ms', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 12.5,
          score: 12.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Performance test classification',
        },
      ];
      result.candidateScores = {
        financial: { score: 12.5, confidence: 12.5, decision: 'selected' },
      };

      const startTime = Date.now();
      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      const endTime = Date.now();

      const processingTime = endTime - startTime;
      expect(processingTime).toBeLessThan(50);
      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeLessThan(50);
    });

    it('should handle large candidate score sets efficiently', () => {
      const largeCandidateScores: Record<string, CandidateScore> = {};
      for (let i = 0; i < 100; i++) {
        largeCandidateScores[`category_${i}`] = {
          score: Math.random() * 10,
          confidence: Math.random() * 10,
          decision: 'candidate',
        };
      }

      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 12.0,
          score: 12.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Large dataset test',
        },
      ];
      result.candidateScores = largeCandidateScores;

      const startTime = Date.now();
      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(100);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
    });
  });

  describe('Threshold Validation and Ordering', () => {
    it('should use correct threshold ordering (low < aiRequired < high)', () => {
      // Test low confidence threshold (3) - create new result for each test
      const result1 = createClassificationResult('test-123', 'session-123', 0);
      result1.selectedLabels = [
        {
          category: 'uncategorized',
          confidence: 2.5,
          score: 2.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'needsReview',
          selectionRationale: 'Below low confidence threshold',
        },
      ];
      result1.candidateScores = {
        uncategorized: { score: 2.5, confidence: 2.5, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result1, mockConfig);
      expect(result1.needsAiClassification).toBe(false);
      expect(result1.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');

      // Test AI required threshold (12) - create new result
      const result2 = createClassificationResult('test-456', 'session-123', 0);
      result2.selectedLabels = [
        {
          category: 'financial',
          confidence: 13.0,
          score: 13.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Above AI required threshold',
        },
      ];
      result2.candidateScores = {
        financial: { score: 13.0, confidence: 13.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result2, mockConfig);
      expect(result2.needsAiClassification).toBe(true);
      expect(result2.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');

      // Test high confidence threshold (15) - create new result
      const result3 = createClassificationResult('test-789', 'session-123', 0);
      result3.selectedLabels = [
        {
          category: 'financial',
          confidence: 16.0,
          score: 16.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Above high confidence threshold',
        },
      ];
      result3.candidateScores = {
        financial: { score: 16.0, confidence: 16.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result3, mockConfig);
      expect(result3.needsAiClassification).toBe(false);
      expect(result3.explainabilityTrace.aiRouting?.reason).toContain('High confidence');
    });

    it('should correctly apply medium confidence range logic', () => {
      // Test score in medium range but below aiRequiredThreshold
      const result1 = createClassificationResult('test-123', 'session-123', 0);
      result1.selectedLabels = [
        {
          category: 'systemNotifications',
          confidence: 7.0, // Between lowConfidence (3) and aiRequiredThreshold (12)
          score: 7.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'serviceStatus',
          selectionRationale: 'Medium confidence below AI routing threshold',
        },
      ];
      result1.candidateScores = {
        systemNotifications: { score: 7.0, confidence: 7.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result1, mockConfig);
      expect(result1.needsAiClassification).toBe(false);
      expect(result1.explainabilityTrace.aiRouting?.reason).toContain('below AI routing threshold');

      // Test score in medium range above aiRequiredThreshold
      const result2 = createClassificationResult('test-123', 'session-123', 0);
      result2.selectedLabels = [
        {
          category: 'actionable',
          confidence: 12.5, // Between aiRequiredThreshold (12) and highConfidence (15)
          score: 12.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'implicitAction',
          selectionRationale: 'Medium confidence above AI routing threshold',
        },
      ];
      result2.candidateScores = {
        actionable: { score: 12.5, confidence: 12.5, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result2, mockConfig);
      expect(result2.needsAiClassification).toBe(true);
      expect(result2.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
      expect(result2.explainabilityTrace.aiRouting?.reason).toContain('AI classification can improve accuracy');
    });

    it('should include threshold values in explainability trace', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 10.0,
          score: 10.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Test threshold documentation',
        },
      ];
      result.candidateScores = {
        financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
      };

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      // Verify threshold values are recorded in explainability trace
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);

      // Verify routing decision is documented
      expect(result.explainabilityTrace.aiRouting?.reason).toBeDefined();
      expect(result.explainabilityTrace.aiRouting?.reason).not.toBe('');
    });
  });
});

