/**
 * Unit Tests for AI Routing Stage
 *
 * Following TDD approach - these tests MUST FAIL before implementation.
 * This stage determines whether emails need AI classification based on confidence scores.
 */

import { aiRoutingStage } from '../../src/stages/ai-routing';
import { CandidateScore } from '../../src/types/classification-result';
import { EmailMessage, ClassificationSession } from '../../src/types';
import { createClassificationResult } from '../../src/utils/initialization';

describe('AI Routing Stage', () => {
  const mockConfig = {
    settings: {
      aiRouting: {
        highConfidenceThreshold: 0.8, // Normalized 0-1 scale (was 15 on absolute scale)
        aiRequiredThreshold: 0.5, // Normalized 0-1 scale (was 12 on absolute scale)
        skipAiConditions: ['hardAssertion'],
      },
    },
    confidenceThresholds: {
      highConfidence: 15,
      mediumConfidence: 8,
      lowConfidence: 3,
      secondaryLabelMinGap: 5,
      aiClassificationRequired: 12,
      manualReviewRequired: 2,
    },
  };

  const mockEmail: EmailMessage = {
    id: 'test-123',
    threadId: 'thread-123',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test email' },
        { name: 'From', value: 'Test User <test@example.com>' },
        { name: 'To', value: 'User <user@example.com>' },
      ],
    },
    subject: 'Test email',
    from: { email: 'test@example.com', name: 'Test User', raw: 'Test User <test@example.com>' },
    to: [{ email: 'user@example.com', name: 'User', raw: 'User <user@example.com>' }],
    bodyPlain: 'Test email body',
    bodyHtml: '<p>Test email body</p>',
    date: new Date('2024-01-01T10:00:00Z'),
    isProcessed: false,
    processingPriority: 1,
  };

  const mockSession: ClassificationSession = {
    id: 'session-123',
    startedAt: new Date('2024-01-01T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'parallel',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-version',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  describe('High Confidence Routing', () => {
    it('should skip AI for high confidence primary labels (>=0.8)', () => {
      // Create properly initialized result
      const result = createClassificationResult('test-123', 'session-123', 0);

      // Populate with high confidence classification data
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 16.5,
          score: 16.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'High confidence financial classification',
        },
      ];
      result.candidateScores = {
        financial: { score: 16.5, confidence: 16.5, decision: 'selected' },
      };
      result.confidence = 0.85; // Normalized 0-1 scale used by AI routing

      // Execute stage - mutates result in place
      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      // Verify routing decision
      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting).toBeDefined();
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('High confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('0.85');
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(0.8);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(0.5);
    });

    it('should skip AI when hard assertion condition is met', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 12.0,
          score: 12.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Hard assertion based on domain match',
        },
      ];
      result.candidateScores = {
        financial: { score: 12.0, confidence: 12.0, decision: 'selected', hardAssertion: true },
      };
      result.confidence = 0.6; // Normalized confidence (hard assertion overrides threshold logic)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('hard assertion');
    });
  });

  describe('Medium Confidence Routing', () => {
    it('should route to AI for medium confidence scores (0.5-0.8)', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'actionable',
          confidence: 10.5,
          score: 10.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'implicitAction',
          selectionRationale: 'Medium confidence actionable classification',
        },
      ];
      result.candidateScores = {
        actionable: { score: 10.5, confidence: 10.5, decision: 'selected' },
        personal: { score: 8.2, confidence: 8.2, decision: 'candidate' },
      };
      result.confidence = 0.65; // Normalized medium confidence (>= 0.5, < 0.8)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('actionable');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('0.65');
    });

    it('should route to AI when multiple labels are selected', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 12.0,
          score: 12.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Primary financial classification',
        },
        {
          category: 'actionable',
          confidence: 9.5,
          score: 9.5,
          isPrimary: false,
          labelOrder: 2,
          subtype: 'implicitAction',
          selectionRationale: 'Secondary actionable classification',
        },
      ];
      result.candidateScores = {
        financial: { score: 12.0, confidence: 12.0, decision: 'selected' },
        actionable: { score: 9.5, confidence: 9.5, decision: 'selected' },
      };
      result.confidence = 0.7; // Normalized medium confidence with multiple labels

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('multiple labels');
    });

    it('should route to AI when close competitors exist', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'commerceLogistics',
          confidence: 11.0,
          score: 11.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'shippingUpdate',
          selectionRationale: 'Close competition with travel category',
        },
      ];
      result.candidateScores = {
        commerceLogistics: { score: 11.0, confidence: 11.0, decision: 'selected' },
        travel: { score: 9.5, confidence: 9.5, decision: 'candidate' },
        personal: { score: 8.8, confidence: 8.8, decision: 'candidate' },
      };
      result.confidence = 0.6; // Normalized medium confidence with close competitors

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('close competing categories');
    });
  });

  describe('Low Confidence Routing', () => {
    it('should skip AI for very low confidence scores (<0.3)', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'uncategorized',
          confidence: 2.1,
          score: 2.1,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'needsReview',
          selectionRationale: 'Very low confidence classification',
        },
      ];
      result.candidateScores = {
        uncategorized: { score: 2.1, confidence: 2.1, decision: 'selected' },
      };
      result.confidence = 0.15; // Normalized very low confidence (< 0.3)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('likely unclassifiable');
    });

    it('should skip AI for scores below AI routing threshold but above low threshold', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'systemNotifications',
          confidence: 6.5,
          score: 6.5,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'serviceStatus',
          selectionRationale: 'Below AI routing threshold',
        },
      ];
      result.candidateScores = {
        systemNotifications: { score: 6.5, confidence: 6.5, decision: 'selected' },
      };
      result.confidence = 0.4; // Normalized medium-low confidence (>= 0.3, < 0.5)

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(false);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('below AI routing threshold');
    });
  });

  describe('No Labels Selected', () => {
    it('should route to AI when no labels are selected', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [];
      result.candidateScores = {};
      result.confidence = 0; // No classification = 0 confidence

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('No labels selected');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('AI may recover');
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing primary label gracefully', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 10.0,
          score: 10.0,
          isPrimary: false,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'No primary flag set',
        },
      ];
      result.candidateScores = {
        financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
      };
      result.confidence = 0.6; // Medium confidence

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      // Should use first label as primary when no primary flag is set
      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
    });

    it('should handle malformed classification input', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: NaN,
          score: NaN,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'receipt',
          selectionRationale: 'Invalid confidence score',
        },
      ];
      result.candidateScores = {};

      expect(() => {
        aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      }).toThrow('Invalid confidence score');
    });

    it('should handle custom confidence thresholds', () => {
      const customConfig = {
        ...mockConfig,
        settings: {
          aiRouting: {
            highConfidenceThreshold: 0.9, // Normalized 0-1 scale (higher than default 0.8)
            aiRequiredThreshold: 0.6, // Normalized 0-1 scale (higher than default 0.5)
            skipAiConditions: [],
          },
        },
      };

      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 18.0,
          score: 18.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'High confidence with custom thresholds',
        },
      ];
      result.candidateScores = {
        financial: { score: 18.0, confidence: 18.0, decision: 'selected' },
      };
      result.confidence = 0.85; // Normalized confidence (< 0.9 high threshold, >= 0.6 AI required)

      aiRoutingStage(mockEmail, mockSession, result, customConfig);

      // With higher threshold (0.9), score of 0.85 should route to AI
      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(0.9);
    });
  });

  describe('Close Competitors Analysis', () => {
    it('should correctly identify close competitors within gap threshold', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'travel',
          confidence: 12.0,
          score: 12.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'flightAlert',
          selectionRationale: 'Travel with commerce logistics competition',
        },
      ];
      result.candidateScores = {
        travel: { score: 12.0, confidence: 12.0, decision: 'selected' },
        commerceLogistics: { score: 10.5, confidence: 10.5, decision: 'candidate' },
        personal: { score: 9.8, confidence: 9.8, decision: 'candidate' },
        financial: { score: 4.0, confidence: 4.0, decision: 'rejected' },
      };
      result.confidence = 0.7; // Medium confidence with close competitors

      aiRoutingStage(mockEmail, mockSession, result, mockConfig);

      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('close competing categories');
    });

    it('should not consider distant competitors as close', () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.selectedLabels = [
        {
          category: 'financial',
          confidence: 14.0,
          score: 14.0,
          isPrimary: true,
          labelOrder: 1,
          subtype: 'statement',
          selectionRationale: 'Clear financial with distant competitors',
        },
      ];
      result.candidateScores = {
