      // Should use first label as primary when no primary flag is set
      expect(result.needsAiClassification).toBe(true);
      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
