      const startTime = Date.now();
      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
      const endTime = Date.now();

      const processingTime = endTime - startTime;
      expect(processingTime).toBeLessThan(50);
      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeLessThan(50);
    });

    it('should handle large candidate score sets efficiently', () => {
      const largeCandidateScores: Record<string, CandidateScore> = {};
      for (let i = 0; i < 100; i++) {
        largeCandidateScores[`category_${i}`] = {
          score: Math.random() * 10,
          confidence: Math.random() * 10,
          decision: 'candidate',
        };
